                        '<button class="simon-action bark" type="button" data-simon-action="bark"><span>\uD83D\uDD0A</span><strong>Ladrar</strong><small>Voz y ondas</small></button>',
                        '<button class="simon-action sit" type="button" data-simon-action="sit"><span>\uD83D\uDC15</span><strong>Sentarse</strong><small>Muy obediente</small></button>',
                        '<button class="simon-action jump" type="button" data-simon-action="jump"><span>\u2728</span><strong>Brincar</strong><small>Salto feliz</small></button>',
                        '<button class="simon-action paw" type="button" data-simon-action="paw"><span>\uD83D\uDC3E</span><strong>Patita</strong><small>Con cari\u00f1o</small></button>',
                    '</div>',
                    '<div class="simon-controls">',
                        '<button class="simon-start" id="simonStartButton" type="button">\uD83D\uDC3E Iniciar Sim\u00f3n</button>',
                        '<button id="simonRepeatButton" type="button" disabled>\u21bb Repetir secuencia</button>',
                        '<button class="simon-give-up" id="simonGiveUpButton" type="button" disabled>\u2691 Rendirse</button>',
