                    '</div>',
                    '<p class="simon-record-note" id="simonRecordNote"></p>',
                    '<label class="simon-nickname">Apodo para guardar el resultado',
                        '<span><input id="simonNickname" maxlength="12" autocomplete="nickname" placeholder="Jugador"><b id="simonNicknameCount">0/12</b></span>',
                    '</label>',
                    '<p class="simon-save-state" id="simonSaveState"></p>',
                    '<div class="simon-result-actions">',
                        '<button class="simon-save-result" id="simonSaveResult" type="button">\uD83C\uDFC6 Guardar resultado</button>',
                        '<button id="simonPlayAgain" type="button">\u21bb Jugar otra vez</button>',
